cssRequirements.css:
@layer priority1 {
  .basex-progress-indicator[data-indeterminate] {
    width: 40% !important;
    animation: basex-progress-indeterminate 1.5s ease-in-out infinite;
  }
  @keyframes basex-progress-indeterminate {
    0% { transform: translateX(-100%); }
    100% { transform: translateX(250%); }
  }
}
